        divisors = set()
        for i in range(1, int(num**0.5) + 1):
            if num % i == 0:
                divisors.add(i)
                divisors.add(num // i)
        return divisors

    def find_sum_of_divisors(num):
        return sum(find_divisors(num)) - num  # Exclude the number itself

