def amicable_numbers_sum(limit: int) -> int:
    """
    Sum all amicable numbers from 1 to limit.
    """
    # Dictionary to store sum of proper divisors for each number
    divisor_sums = {}

    # Calculate sum of proper divisors for all numbers up to limit
    for i in range(1, limit + 1):
        divisor_sums[i] = 0

    # For each number, add it to the divisor sums of its multiples
    for i in range(1, limit + 1):
        for j in range(2 * i, limit + 1, i):
            divisor_sums[j] += i

    # Find amicable pairs and sum them
    amicable_sum = 0
    for i in range(2, limit + 1):
        j = divisor_sums[i]
        # Check if j is an amicable partner of i
        if j != i and divisor_sums[j] == i and j <= limit:
            amicable_sum += i + j

    return amicable_sum
