def sum_common_divisors(a, b):
    """
    Calculate the sum of the common divisors of two given numbers.
    """
    if a == 0 and b == 0:
        return 0  # All numbers are divisors of 0, but this is a special case.
    if a == 0 or b == 0:
        return 0  # No common divisors other than 0, but 0 is not a divisor.

    # Find the smaller number to limit the range of potential divisors.
    min_num = min(a, b)
    total_sum = 0

    # Iterate through all potential divisors up to the square root of min_num.
    # This is an optimization.
    for i in range(1, int(min_num ** 0.5) + 1):
        if min_num % i == 0:
            # i is a divisor
            if min_num // i == i:
                # If i is the square root, add it only once.
                if min_num // i == i and min_num // i <= a and min_num // i <= b:
                    total_sum += min_num // i
            else:
                # Check if i is a common divisor.
                if min_num % i == 0 and a % i == 0 and b % i == 0:
                    total_sum += i
                # Check if the pair divisor (min_num // i) is a common divisor.
                pair_divisor = min_num // i
                if a % pair_divisor == 0 and b % pair_divisor == 0:
                    total_sum += pair_divisor

    return total_sum
