def find_solution(a, b, n):
    """
    Returns integers x and y that satisfy ax + by = n as a tuple,
    or returns None if no solution exists.
    """
    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)
    if a == 0:
        return (0, n // b) if n % b == 0 else None
    if b == 0:
        return (n // a, 0) if n % a == 0 else None

    # Extended Euclidean Algorithm to find x0, y0 such that ax0 + by0 = gcd(a, b)
    def extended_gcd(a, b):
        if b == 0:
            return a, 1, 0
        gcd, x1, y1 = extended_gcd(b, a % b)
        x = y1
        y = x1 - (a // b) * y1
        return gcd, x, y

    gcd, x0, y0 = extended_gcd(a, b)
    if n % gcd != 0:
        return None

    # Scale the solution
    x = x0 * (n // gcd)
    y = y0 * (n // gcd)
    return (x, y)
