def find_solution(a, b, n):
    """
    Returns a tuple (x, y) such that ax + by = n, or None if no solution exists.
    """
    if a == 0 and b == 0:
        if n == 0:
            return (0, 0)
        return None

    # If one of a or b is zero, the equation simplifies
    if a == 0:
        if n % b == 0:
            return (0, n // b)
        return None
    if b == 0:
        if n % a == 0:
            return (n // a, 0)
        return None

    # Use the Extended Euclidean Algorithm to find the GCD and coefficients
    # We find x0, y0 such that a*x0 + b*y0 = gcd(a, b)
    old_r, r = a, b
    old_s, s = 1, 0
    old_t, t = 0, 1

    while r != 0:
        quotient = old_r // r
        old_r, r = r, old_r - quotient * r
        old_s, s = s, old_s - quotient * s
        old_t, t = t, old_t - quotient * t

    gcd = old_r

    # If gcd does not divide n, there is no solution
    if n % gcd != 0:
        return None

    # Scale the coefficients
    x0 = old_s * (n // gcd)
    y0 = old_t * (n // gcd)

    return (x0, y0)
