def get_total_number_of_sequences(m, n):
    # Memoization dictionary for dynamic programming
    memo = {}

    def dp(prev, length):
        # Base case: if length is 0, there's one valid sequence (empty)
        if length == 0:
            return 1
        # Base case: if length is negative, invalid
        if length < 0:
            return 0

        # Check if result is already computed
        if (prev, length) in memo:
            return memo[(prev, length)]

        total = 0
        # Iterate over possible next elements
        # Next element must be >= 2*prev and <= m
        start = max(2 * prev, 1)
        end = m
        for next_val in range(start, end + 1):
            total += dp(next_val, length - 1)

        memo[(prev, length)] = total
        return total

    # Start with prev=1 (smallest possible starting value) and length=n
    return dp(1, n)
