import math

def newman_prime(n):
    """
    Returns the nth Newman–Shanks–Williams prime.
    """
    def is_prime(num):
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        sqrt_n = int(math.sqrt(num)) + 1
        for i in range(3, sqrt_n, 2):
            if num % i == 0:
                return False
        return True

    def generate_nsw(k):
        """
        Generates the k-th Newman-Shanks-Williams number.
        """
        if k == 1:
            return 1
        if k == 2:
            return 1
        a, b = 1, 1
        for i in range(3, k + 1):
            a, b = b, 2 * b + a
        return b

    count = 0
    k = 1
    while count < n:
        num = generate_nsw(k)
        if is_prime(num):
            count += 1
            if count == n:
                return num
        k += 1

