        return []

    # Group the tuples by their first element
    groups = {}
    for t in tuples:
        key = t[0]
        if key not in groups:
            groups[key] = []
        groups[key].append(t)

    # Convert the groups back into a list of tuples
    result = []
    for key, group in groups.items():
        # Extract all elements from the tuples in the group
        elements = []
        for t in group:
            elements.extend(t[1:])  # Skip the first element as it's the key
        result.append((key, *elements))

