def max_product(arr):
    n = len(arr)
    if n == 0:
        return 0
    if n == 1:
        return arr[0]

    # dp[i] will store the maximum product of an increasing subsequence ending at index i.
    dp = arr[:]  # Initialize dp with the array values.
    max_product = arr[0]

    for i in range(1, n):
        for j in range(i):
            if arr[j] < arr[i]:
